SELECT name 
FROM vendors 
WHERE vendor_id IN (SELECT vendor_id FROM package_vendors);

SELECT COUNT(package_id) AS package_count
FROM package_vendors
WHERE vendor_id = 1;

SELECT name
FROM packages
ORDER BY name;

SELECT MAX(change_date)
FROM change_history
WHERE package_id = 1;

SELECT COUNT(change_id) AS total_changes
FROM change_history
WHERE change_date < '2020-06-01';
